+struct MatRpeatParam {
+    uint32_t row;
+    uint32_t col;
+    uint32_t dtypeMask;
+    uint32_t loopTimes;
+    uint32_t colRemain;
+    uint8_t repeatStride;
+};
+
+struct RmsNormParam {
+    float reciprocal;
+    float epsilon;
+    uint32_t row;
+    uint32_t col;
+};
