+template <typename COMP>
+__aicore__ inline uint32_t CompressorBlockVectorPerf<COMP>::GetStartPos(uint32_t bIdx)
+{
+    if (isExistStartPos) {
+        return startPosGm_.GetValue(bIdx);
+    }
+    return 0;
+}
