+template <typename COMP>
+__aicore__ inline uint32_t CompressorBlockVectorPerf<COMP>::GetBsLength(uint32_t index)
+{
+    if (COMP::xLayout == X_LAYOUT::TH) {
+        return cuSeqlensGm_.GetValue(index);
+    } else {
+        return index * constInfo_.sSize;
+    }
+}
