+                MicroAPI::DataCopy<ROPET, MicroAPI::LoadDist::DIST_UNPACK_B16>(sinFp16R, tailSinUb + VL_FLOAT32_SIZE);
+                MicroAPI::DataCopy<ROPET, MicroAPI::LoadDist::DIST_UNPACK_B16>(cosFp16Q, tailCosUb);
