+                    vregExp2, pregAll);
+                StoreAlign<T, MicroAPI::StoreDist::DIST_NORM>(((__ubuf__ T *&)srcUb3 + loopM * RowSize + ReduceSize * RowSize * loopSc * 4),
+                    vregExp3, pregAll);
