+#define INVOKE_COMPRESSOR_GENERAL_OP_IMPL(templateClass, ...)                                                          \
+    do {                                                                                                               \
+        templateClass<COMPType<__VA_ARGS__>> op(&pipe, tilingData);                                                    \
+        op.Init(x, wKv, wGate, stateCache, ape, normWeight, ropeSin, ropeCos, stateBlockTable,  \
