+/*!
+ * \file rotary_position_embedding.cc
+ * \brief
+ */
+#include "inplace_partial_rotary_mul_tiling.h"
+#include "register/op_def_registry.h"
+// #include "log/log.h"
+#include "tiling/tiling_api.h"
