+template <typename T>
+static inline T CeilDiv(T num, T rnd)
+{
+    return (((rnd) == 0) ? 0 : (((num) + (rnd) - 1) / (rnd)));
+}
+
+template <typename T>
+static inline T CeilAlign(T num, T rnd)
+{
+    return (((rnd) == 0) ? 0 : (((num) + (rnd) - 1) / (rnd)) * (rnd));
+}
+
+template <typename T>
+static inline T FloorDiv(T x, T y)
+{
+    if (y == 0)
+    {
+        return 0;
+    }
+    return x / y;
+}
+
+template <typename T>
+static inline T FloorAlign(T x, T y)
+{
+    if (y == 0)
+    {
+        return 0;
+    }
+    return x / y * y;
+}
