+template <typename T1, typename T2>
+__aicore__ inline T1 CeilDiv(T1 x, T2 y)
+{
+    if (y != 0 && x != 0) {
+        const T1 quotient = x / y;
+        return (x % y != 0 && ((x ^ y) >= 0)) ? (quotient + 1) : quotient;
+    }
+
+    return x;
