+    TQue<QuePosition::VECOUT, DOUBLE_BUFFER> outQueueY;
+    TBuf<TPosition::VECCALC> xBuf;
+    TBuf<TPosition::VECCALC> xNewBuf;
+    TBuf<TPosition::VECCALC> cosBuf;
+    TBuf<TPosition::VECCALC> sinBuf;
