+/*!
+ * \file rotate_interleaved_common.h
+ * \brief
+ */
+#ifndef ROTATE_INTERLEAVED_COMMON_H
+#define ROTATE_INTERLEAVED_COMMON_H
+#include "kernel_operator.h"
+#include "impl/dav_c220/kernel_operator_reg_others_impl.h"
